+import AppKit
+import Foundation
+
+struct PasteboardItemSnapshot: Equatable, Sendable {
+    let representations: [String: Data]
+}
+
+struct PasteboardSnapshot: Equatable, Sendable {
+    let items: [PasteboardItemSnapshot]
+}
+
+protocol RawPasteboardItem {
+    var types: [String] { get }
+    func data(forType type: String) -> Data?
+}
+
+protocol RawPasteboard: AnyObject {
+    var items: [any RawPasteboardItem] { get }
+    func clearContents()
+    func setString(_ string: String, forType type: String)
+    func writeItems(_ items: [[String: Data]])
+}
+
+protocol PasteboardControlling: AnyObject {
+    func captureContents() -> PasteboardSnapshot?
+    func writePlainText(_ text: String)
+    func restoreContents(_ snapshot: PasteboardSnapshot)
+}
+
+final class GeneralPasteboardController: PasteboardControlling {
+    private let pasteboard: any RawPasteboard
+
+    init(pasteboard: any RawPasteboard = NSPasteboardAdapter()) {
+        self.pasteboard = pasteboard
+    }
+
+    func captureContents() -> PasteboardSnapshot? {
+        let snapshots = pasteboard.items.map { item in
+            PasteboardItemSnapshot(representations: Dictionary(uniqueKeysWithValues: item.types.compactMap { type in
+                item.data(forType: type).map { (type, $0) }
+            }))
+        }
+
+        guard !snapshots.isEmpty else {
+            return nil
+        }
+
+        return PasteboardSnapshot(items: snapshots)
+    }
+
+    func writePlainText(_ text: String) {
+        pasteboard.clearContents()
+        pasteboard.setString(text, forType: NSPasteboard.PasteboardType.string.rawValue)
+    }
+
+    func restoreContents(_ snapshot: PasteboardSnapshot) {
+        pasteboard.clearContents()
+        pasteboard.writeItems(snapshot.items.map(\.representations))
+    }
+}
+
+final class NSPasteboardAdapter: RawPasteboard {
+    private let pasteboard: NSPasteboard
+
+    init(pasteboard: NSPasteboard = .general) {
+        self.pasteboard = pasteboard
+    }
+
+    var items: [any RawPasteboardItem] {
+        (pasteboard.pasteboardItems ?? []).map(NSPasteboardItemAdapter.init)
+    }
+
+    func clearContents() {
+        pasteboard.clearContents()
+    }
+
+    func setString(_ string: String, forType type: String) {
+        pasteboard.setString(string, forType: NSPasteboard.PasteboardType(type))
+    }
+
+    func writeItems(_ items: [[String: Data]]) {
+        let restoredItems = items.map { representations in
+            let item = NSPasteboardItem()
+            for (type, data) in representations {
+                item.setData(data, forType: NSPasteboard.PasteboardType(type))
+            }
+            return item
+        }
+
+        pasteboard.writeObjects(restoredItems)
+    }
+}
+
+private struct NSPasteboardItemAdapter: RawPasteboardItem {
+    let item: NSPasteboardItem
+
+    var types: [String] {
+        item.types.map(\.rawValue)
+    }
+
+    func data(forType type: String) -> Data? {
+        item.data(forType: NSPasteboard.PasteboardType(type))
+    }
+}

