+import CoreGraphics
+import Foundation
+
+enum PasteDeliveryResult: Equatable, Sendable {
+    case pasted
+    case copiedToClipboard
+}
+
+struct PasteSessionSnapshot: Equatable, Sendable {
+    let pastedText: String
+    let timestamp: Date
+    let applicationBundleIdentifier: String?
+    let windowID: Int?
+    let windowFrame: CGRect?
+    let focusedElementFrame: CGRect?
+    let focusedElementText: String?
+}
+
+struct PasteLifecycleCallbacks {
+    var onPasteStart: () -> Void = {}
+    var onPasteSession: (PasteSessionSnapshot) -> Void = { _ in }
+    var onPasteEnd: (PasteDeliveryResult) -> Void = { _ in }
+}
+
+typealias PreparedPasteAction = () -> Void
+
+protocol PasteTargetDetecting: AnyObject {
+    func canPasteToFocusedElement() -> Bool
+}
+
+protocol PasteKeystrokePreparing: AnyObject {
+    func makePreparedPaste() -> PreparedPasteAction?
+}
+
+protocol PasteSessionCapturing: AnyObject {
+    func capture(pastedText: String) -> PasteSessionSnapshot?
+}
+
+@MainActor
+protocol DelaySleeping: AnyObject {
+    func sleep(for duration: Duration) async
+}
+
+@MainActor
+final class TaskDelaySleeper: DelaySleeping {
+    func sleep(for duration: Duration) async {
+        try? await Task.sleep(for: duration)
+    }
+}
+
+@MainActor
+protocol TextPasteDelivering: AnyObject {
+    func deliver(_ text: String, callbacks: PasteLifecycleCallbacks) async -> PasteDeliveryResult
+}
+
+@MainActor
+final class TextPasteDeliverer: TextPasteDelivering {
+    private let pasteboard: any PasteboardControlling
+    private let targetDetector: any PasteTargetDetecting
+    private let keystrokePreparer: any PasteKeystrokePreparing
+    private let sessionCapturer: any PasteSessionCapturing
+    private let sleeper: any DelaySleeping
+
+    init(
+        pasteboard: any PasteboardControlling,
+        targetDetector: any PasteTargetDetecting,
+        keystrokePreparer: any PasteKeystrokePreparing,
+        sessionCapturer: any PasteSessionCapturing,
+        sleeper: any DelaySleeping = TaskDelaySleeper()
+    ) {
+        self.pasteboard = pasteboard
+        self.targetDetector = targetDetector
+        self.keystrokePreparer = keystrokePreparer
+        self.sessionCapturer = sessionCapturer
+        self.sleeper = sleeper
+    }
+
+    func deliver(_ text: String, callbacks: PasteLifecycleCallbacks = PasteLifecycleCallbacks()) async -> PasteDeliveryResult {
+        callbacks.onPasteStart()
+
+        let preservedClipboard = pasteboard.captureContents()
+        pasteboard.writePlainText(text)
+
+        guard targetDetector.canPasteToFocusedElement() else {
+            callbacks.onPasteEnd(.copiedToClipboard)
+            return .copiedToClipboard
+        }
+
+        guard let preparedPaste = keystrokePreparer.makePreparedPaste() else {
+            callbacks.onPasteEnd(.copiedToClipboard)
+            return .copiedToClipboard
+        }
+
+        await sleeper.sleep(for: .milliseconds(50))
+        preparedPaste()
+        await sleeper.sleep(for: .milliseconds(100))
+
+        if let snapshot = sessionCapturer.capture(pastedText: text) {
+            callbacks.onPasteSession(snapshot)
+        }
+
+        if let preservedClipboard {
+            pasteboard.restoreContents(preservedClipboard)
+        }
+
+        callbacks.onPasteEnd(.pasted)
+        return .pasted
+    }
+}
